def remove_peripheral_zeros(im):
    if im.size == 0:
        return np.array([])

    rows = np.any(im, axis=1)
    cols = np.any(im, axis=0)

    if not np.any(rows) or not np.any(cols):
        return np.array([])

    r_start = np.argmax(rows)
    r_end = np.argmax(np.flip(rows))
