def smoothclamp(x, x_min, x_max, N):
    t = (x - x_min) / (x_max - x_min)
    t = np.clip(t, 0.0, 1.0)
    result = 0.0
    for n in range(0, N + 1):
        result += comb(N + n, n) * comb(2 * N + 1, N - n) * (-t) ** n
    result *= t ** (N + 1)
    return x_min + (x_max - x_min) * result

def comb(n, k):
    if k < 0 or k > n:
        return 0
    if k == 0 or k == n:
        return 1
    k = min(k, n - k)
    c = 1
    for i in range(k):
        c = c * (n - i) // (i + 1)
    return c
